			// Pull latest changes
			slog.Info("updating remote repo", "path", localPath, "hasToken", pullToken != "")
			cmd := gitPullCmd(ctx, localPath, pullToken, sshKeyPath)
			if err := cmd.Run(); err != nil {
				slog.Warn("git pull failed, proceeding with current state", "error", err)
			}
