// Repositories is the resolver for the repositories field.
func (r *queryResolver) Repositories(ctx context.Context) ([]*Repository, error) {
	if r.getStore(ctx) == nil {
		return []*Repository{}, nil
	}

	store := r.getStore(ctx)
	graphRepos := store.ListRepositories()
	var repos []*Repository
	for _, gr := range graphRepos {
		repo := mapRepository(gr)
		_, reqCount := store.GetRequirements(gr.ID, 0, 0)
		repo.RequirementCount = reqCount
		repos = append(repos, repo)
	}
	return repos, nil
}

// Repository is the resolver for the repository field.
func (r *queryResolver) Repository(ctx context.Context, id string) (*Repository, error) {
	if r.getStore(ctx) == nil {
		return nil, fmt.Errorf("store not initialized")
	}

	gr := r.getStore(ctx).GetRepository(id)
	if gr == nil {
		return nil, fmt.Errorf("repository not found: %s", id)
	}
	store := r.getStore(ctx)
	repo := mapRepository(gr)
	_, reqCount := store.GetRequirements(gr.ID, 0, 0)
	repo.RequirementCount = reqCount
	populateRepositoryDetails(repo, store)
	return repo, nil
}

// Symbols is the resolver for the symbols field.
func (r *queryResolver) Symbols(ctx context.Context, repositoryID string, query *string, filePath *string, kind *SymbolKind, limit *int, offset *int) (*SymbolConnection, error) {
	if r.getStore(ctx) == nil {
		return &SymbolConnection{Nodes: []*CodeSymbol{}, TotalCount: 0}, nil
	}

	// If filePath is provided, use the file-based lookup
	if filePath != nil && *filePath != "" {
		syms := r.getStore(ctx).GetSymbolsByFile(repositoryID, *filePath)
		var nodes []*CodeSymbol
		for _, s := range syms {
			if kind != nil {
				k := strings.ToLower(string(*kind))
				if s.Kind != k {
					continue
				}
			}
			sym := mapSymbol(s)
			populateSymbolRelations(sym, r.getStore(ctx))
			nodes = append(nodes, sym)
		}
		return &SymbolConnection{Nodes: nodes, TotalCount: len(nodes)}, nil
	}

	var kindStr *string
	if kind != nil {
		s := strings.ToLower(string(*kind))
		kindStr = &s
	}
	lim := 100
	off := 0
	if limit != nil {
		lim = *limit
	}
	if offset != nil {
		off = *offset
	}

	var queryStr *string
	if query != nil {
		queryStr = query
	}

	syms, total := r.getStore(ctx).GetSymbols(repositoryID, queryStr, kindStr, lim, off)
	var nodes []*CodeSymbol
	for _, s := range syms {
		sym := mapSymbol(s)
		populateSymbolRelations(sym, r.getStore(ctx))
		nodes = append(nodes, sym)
	}
	return &SymbolConnection{Nodes: nodes, TotalCount: total}, nil
}

// Requirements is the resolver for the requirements field.
func (r *queryResolver) Requirements(ctx context.Context, repositoryID string, limit *int, offset *int) (*RequirementConnection, error) {
	if r.getStore(ctx) == nil {
		return &RequirementConnection{Nodes: []*Requirement{}, TotalCount: 0}, nil
	}

	lim := 100
	off := 0
	if limit != nil {
		lim = *limit
	}
	if offset != nil {
		off = *offset
	}

	reqs, total := r.getStore(ctx).GetRequirements(repositoryID, lim, off)
	var nodes []*Requirement
	for _, req := range reqs {
		nodes = append(nodes, mapRequirement(req))
	}
	return &RequirementConnection{Nodes: nodes, TotalCount: total}, nil
}

