// Search is the resolver for the search field.
func (r *queryResolver) Search(ctx context.Context, query string, repositoryID *string, limit *int) ([]*SearchResult, error) {
	if r.getStore(ctx) == nil {
		return []*SearchResult{}, nil
	}

	maxResults := 50
	if limit != nil && *limit > 0 && *limit < 200 {
		maxResults = *limit
	}

	var results []*SearchResult
	queryLower := strings.ToLower(query)

	// Search across all repositories
	repos := r.getStore(ctx).ListRepositories()
	for _, repo := range repos {
		if repositoryID != nil && *repositoryID != "" && repo.ID != *repositoryID {
			continue
		}

		// Search symbols
		symbols, _ := r.getStore(ctx).GetSymbols(repo.ID, nil, nil, 0, 0)
		for _, sym := range symbols {
			if len(results) >= maxResults {
				break
			}
			nameLower := strings.ToLower(sym.Name)
			qualLower := strings.ToLower(sym.QualifiedName)
			if strings.Contains(nameLower, queryLower) || strings.Contains(qualLower, queryLower) {
				fp := sym.FilePath
				sl := sym.StartLine
				results = append(results, &SearchResult{
					Type:           "symbol",
					ID:             sym.ID,
					Title:          sym.Name,
					Description:    &sym.QualifiedName,
					FilePath:       &fp,
					Line:           &sl,
					RepositoryID:   repo.ID,
					RepositoryName: repo.Name,
				})
			}
		}

		// Search requirements
		reqs, _ := r.getStore(ctx).GetRequirements(repo.ID, 0, 0)
		for _, req := range reqs {
			if len(results) >= maxResults {
				break
			}
			titleLower := strings.ToLower(req.Title)
			descLower := strings.ToLower(req.Description)
			extLower := strings.ToLower(req.ExternalID)
			if strings.Contains(titleLower, queryLower) || strings.Contains(descLower, queryLower) || strings.Contains(extLower, queryLower) {
				desc := req.Description
				results = append(results, &SearchResult{
					Type:           "requirement",
					ID:             req.ID,
					Title:          req.ExternalID + ": " + req.Title,
					Description:    &desc,
					RepositoryID:   repo.ID,
					RepositoryName: repo.Name,
				})
			}
		}

		// Search files
		files := r.getStore(ctx).GetFiles(repo.ID)
		for _, f := range files {
			if len(results) >= maxResults {
				break
			}
			pathLower := strings.ToLower(f.Path)
			if strings.Contains(pathLower, queryLower) {
				fp := f.Path
				results = append(results, &SearchResult{
					Type:           "file",
					ID:             f.ID,
					Title:          f.Path,
					FilePath:       &fp,
					RepositoryID:   repo.ID,
					RepositoryName: repo.Name,
				})
			}
		}
	}

	return results, nil
}

// TraceabilityMatrix is the resolver for the traceabilityMatrix field.
func (r *queryResolver) TraceabilityMatrix(ctx context.Context, repositoryID string) (*TraceabilityMatrix, error) {
	if r.getStore(ctx) == nil {
		return &TraceabilityMatrix{
			Requirements: []*Requirement{},
			Symbols:      []*CodeSymbol{},
			Links:        []*RequirementLink{},
			Coverage:     0,
		}, nil
	}

	reqs, _ := r.getStore(ctx).GetRequirements(repositoryID, 10000, 0)
	links := r.getStore(ctx).GetLinksForRepo(repositoryID)

	// Build result
	var gqlReqs []*Requirement
	for _, req := range reqs {
		gqlReqs = append(gqlReqs, mapRequirement(req))
	}

	var gqlLinks []*RequirementLink
	symbolSet := make(map[string]bool)
	for _, l := range links {
		gqlLinks = append(gqlLinks, mapLink(l))
		symbolSet[l.SymbolID] = true
	}

	// Collect unique linked symbols
	var gqlSyms []*CodeSymbol
	syms, _ := r.getStore(ctx).GetSymbols(repositoryID, nil, nil, 10000, 0)
	for _, s := range syms {
		if symbolSet[s.ID] {
			gqlSyms = append(gqlSyms, mapSymbol(s))
		}
	}

	// Coverage = requirements with at least one link / total requirements
	linkedReqs := make(map[string]bool)
	for _, l := range links {
		linkedReqs[l.RequirementID] = true
	}
	coverage := 0.0
	if len(reqs) > 0 {
		coverage = float64(len(linkedReqs)) / float64(len(reqs))
	}

	if gqlReqs == nil {
		gqlReqs = []*Requirement{}
	}
	if gqlSyms == nil {
		gqlSyms = []*CodeSymbol{}
	}
	if gqlLinks == nil {
		gqlLinks = []*RequirementLink{}
	}

	return &TraceabilityMatrix{
		Requirements: gqlReqs,
		Symbols:      gqlSyms,
		Links:        gqlLinks,
		Coverage:     coverage,
	}, nil
}

// RequirementToCode is the resolver for the requirementToCode field.
