// PlatformStats is the resolver for the platformStats field.
func (r *queryResolver) PlatformStats(ctx context.Context) (*PlatformStats, error) {
	if r.getStore(ctx) == nil {
		return &PlatformStats{}, nil
	}
	stats := r.getStore(ctx).Stats()

	// Sum LLM token usage
	usage := r.getStore(ctx).GetLLMUsage("", 0)
	totalIn, totalOut := 0, 0
	for _, u := range usage {
		totalIn += u.InputTokens
		totalOut += u.OutputTokens
	}

	return &PlatformStats{
		Repositories:      stats["repositories"],
		Files:             stats["files"],
		Symbols:           stats["symbols"],
		Requirements:      stats["requirements"],
		Links:             stats["links"],
		TotalInputTokens:  totalIn,
		TotalOutputTokens: totalOut,
	}, nil
}

// Files is the resolver for the files field.
func (r *repositoryResolver) Files(ctx context.Context, obj *Repository, limit *int, offset *int, path *string) (*FileConnection, error) {
	store := r.getStore(ctx)
	if store == nil {
		return &FileConnection{Nodes: []*File{}, TotalCount: 0}, nil
	}

	lim := 100
	off := 0
	if limit != nil {
		lim = *limit
	}
	if offset != nil {
		off = *offset
	}

	files, total := store.GetFilesPaginated(obj.ID, path, lim, off)
	nodes := make([]*File, 0, len(files))
	for _, f := range files {
		nodes = append(nodes, mapFile(f))
	}
	return &FileConnection{Nodes: nodes, TotalCount: total}, nil
}

// UnderstandingScore is the resolver for the understandingScore field.
func (r *repositoryResolver) UnderstandingScore(ctx context.Context, obj *Repository) (*UnderstandingScore, error) {
	store := r.getStore(ctx)
	if store == nil {
		return nil, nil
	}

	// Always compute the full score so sub-score breakdowns are populated.
	// The cache only stores the overall value, so using it would zero out
	// the breakdown fields (traceability, documentation, review, test, knowledge).
	score := graphstore.ComputeUnderstandingScore(store, newKnowledgeFreshnessProvider(r.KnowledgeStore), obj.ID)
	store.CacheUnderstandingScore(obj.ID, score.Overall)
	return mapUnderstandingScore(score), nil
}

// Mutation returns MutationResolver implementation.
func (r *Resolver) Mutation() MutationResolver { return &mutationResolver{r} }

// Query returns QueryResolver implementation.
func (r *Resolver) Query() QueryResolver { return &queryResolver{r} }

// Repository returns RepositoryResolver implementation.
func (r *Resolver) Repository() RepositoryResolver { return &repositoryResolver{r} }

type mutationResolver struct{ *Resolver }
type queryResolver struct{ *Resolver }
type repositoryResolver struct{ *Resolver }
